			pullRequestNumber: input.pullRequestNumber,
			pullRequestUrl: input.pullRequestUrl,
			classification,
			attemptCounts,
			maxAttempts,
			repairExecutionKey,
			failureFingerprint,
		},
	});

	const decisionId = await createDecision(client, {
