				repairExecutionKey,
			},
		}),
		updateWorkerRunStatus(client, {
			id: workerRun.id,
			status: "completed",
		}),
	]);

	return {
		workerRunId: workerRun.id,
		decisionId,
		outcome,
		classification,
		attemptCount: attemptCounts.headSha,
		attemptCounts,
		maxAttempts,
		repairExecutionKey,
		failureFingerprint,
	};
}

