test("classifyRepair detects format-only failed checks", () => {
	const summary: PullRequestCheckSummary = {
		classification: "ci_failed",
		status: "failure",
		headSha: "sha-1",
		checkRuns: [
			{
				name: "biome check",
				status: "completed",
				conclusion: "failure",
				detailsUrl: null,
			},
			{
				name: "tsc",
				status: "completed",
				conclusion: "success",
				detailsUrl: null,
			},
		],
	};

	const mixed = classifyRepair({
		...summary,
		checkRuns: [
			{
				name: "format check",
				status: "completed",
				conclusion: "failure",
				detailsUrl: null,
			},
			{
				name: "unit tests",
				status: "completed",
				conclusion: "failure",
				detailsUrl: null,
			},
		],
	});

	const none = classifyRepair({
		...summary,
		classification: "checks_success",
	});

	const formatOnly = classifyRepair({
		...summary,
		checkRuns: [
			{
				name: "prettier",
				status: "completed",
				conclusion: "failure",
				detailsUrl: null,
			},
		],
	});

	const checksUnknown = classifyRepair({
		...summary,
		checkRuns: [
			{
				name: "lint",
				status: "completed",
				conclusion: "timed_out",
				detailsUrl: null,
			},
		],
	});

	expect(none).toBe("not_deterministically_fixable");
	expect(mixed).toBe("not_deterministically_fixable");
	expect(formatOnly).toBe("format_fixable");
	expect(checksUnknown).toBe("not_deterministically_fixable");
	expect(summary.headSha).toBe("sha-1");
});

test("classifyRepair matches configured workflow, job, and failed step metadata", () => {
	const repairConfig = parseRepairConfig(`
[repair]

[[repair.format_checks]]
workflow_path = ".github/workflows/ci.yml"
job_name = "Static checks"
step_names = ["Format check"]
`);

	const summary: PullRequestCheckSummary = {
		classification: "ci_failed",
		headSha: "sha-config-match",
		status: "failure",
		checkRuns: [
			{
				name: "Static checks",
				status: "completed",
				conclusion: "failure",
				detailsUrl:
					"https://github.com/toyamarinyon/rhapsody/actions/runs/1/job/2",
				actions: {
					workflowRunId: 1,
					workflowName: "CI",
					workflowPath: ".github/workflows/ci.yml",
					jobId: 2,
					jobName: "Static checks",
					failedStepNames: ["Format check"],
				},
			},
		],
	};

	expect(classifyRepair(summary, repairConfig)).toBe("format_fixable");
});

